#include<bits/stdc++.h>
using namespace std;
vector<long long> v,res;
int main()
{
    long long ans=0;
    long long n,m;
    scanf("%lld%lld",&n,&m);
    for(long long i=1;i<=n;i++)
    {
        long long c;
        scanf("%lld",&c);
        v.clear();
        for(long long j=1;j<=c;j++)
        {
            long long x;
            scanf("%lld",&x);
            v.push_back(x);
        }
        sort(v.begin(),v.end());
        long long k=v.size();
        for(long long j=0;j<k-1;j++)
        {
            res.push_back(v[j+1]-v[j]-1);
        }
        ans+=v[c-1]-v[0]+1;
    }
    sort(res.begin(),res.end(),greater<long long>());
    for(long long i=0;i<min((long long)(res.size()),m-1)&&res[i]>0;i++)
    {
        ans-=res[i];
    }
    printf("%lld",ans);
    return 0;
}
